package com.treeeducation.ioas.media.assetfile; import io.swagger.v3.oas.annotations.media.Schema; /** Asset file DTOs. */ public final class AssetFileDtos{private AssetFileDtos(){} @Schema(description="素材文件响应") public record Response(Long id,Long packageId,AssetFileType type,String originalName,String objectKey,String bucketName,String previewUrl,String thumbnailUrl,String mimeType,Long fileSize,String description,Boolean isDeleted){} public static Response of(AssetFile f){return new Response(f.getId(),f.getPackageId(),f.getType(),f.getOriginalName(),f.getObjectKey(),f.getBucketName(),f.getPreviewUrl(),f.getThumbnailUrl(),f.getMimeType(),f.getFileSize(),f.getDescription(),f.getIsDeleted());}}
